    // Wrap script logic in a check for the container element
    const reviewsComponent = document.getElementById('customer-reviews-component');

    if (reviewsComponent) {
        // Get DOM elements relative to the component container
        const sliderWrapper = reviewsComponent.querySelector('.review-slider-wrapper');
        const prevButton = reviewsComponent.querySelector('.slider-nav.prev');
        const nextButton = reviewsComponent.querySelector('.slider-nav.next');
        const reviewCards = reviewsComponent.querySelectorAll('.review-card');
        const sliderContainer = reviewsComponent.querySelector('.review-slider-container');

        // Configuration
        const totalCards = reviewCards.length;
        let currentIndex = 0;
        let cardsPerPage = getCardsPerPage();
        const gap = 20;

        // --- Functions ---
        function getCardsPerPage() {
             if (!sliderContainer) return 3;
             const containerInnerWidth = sliderContainer.offsetWidth;
             let cardWidthEstimate = 300;
             if (reviewCards.length > 0) {
                  cardWidthEstimate = reviewCards[0].offsetWidth;
             }
             if (cardWidthEstimate <= 0) cardWidthEstimate = 300;

             if (containerInnerWidth >= 900) {
                  return 3;
             } else if (containerInnerWidth >= 600) {
                  return 2;
             } else {
                 return 1;
             }
        }

        function updateSliderPosition() {
            if (reviewCards.length === 0 || !sliderWrapper) return;
            const cardWidth = reviewCards[0].offsetWidth;
            const safeCardsPerPage = Math.max(1, getCardsPerPage());
            // Ensure currentIndex doesn't exceed valid range
            const maxPossibleIndex = Math.max(0, totalCards - safeCardsPerPage);
            const safeIndex = Math.max(0, Math.min(currentIndex, maxPossibleIndex));
            const totalWidthToTranslate = safeIndex * (cardWidth + gap);
            sliderWrapper.style.transform = `translateX(-${totalWidthToTranslate}px)`;
            updateButtonStates();
        }

        function updateButtonStates() {
             if (!prevButton || !nextButton) return;

            const safeCardsPerPage = Math.max(1, getCardsPerPage());
            const maxPossibleIndex = Math.max(0, totalCards - safeCardsPerPage);
            const safeIndex = Math.max(0, Math.min(currentIndex, maxPossibleIndex));

             prevButton.disabled = safeIndex === 0;
             nextButton.disabled = safeIndex >= maxPossibleIndex; // Use maxPossibleIndex

             if (totalCards <= safeCardsPerPage) {
                 prevButton.disabled = true;
                 nextButton.disabled = true;
             }
        }

        function slideNext() {
            const safeCardsPerPage = Math.max(1, getCardsPerPage());
            const maxIndex = Math.max(0, totalCards - safeCardsPerPage);
            currentIndex = Math.min(currentIndex + 1, maxIndex);
            updateSliderPosition();
        }

        function slidePrev() {
            currentIndex = Math.max(currentIndex - 1, 0);
            updateSliderPosition();
        }

        function handleResize() {
             cardsPerPage = getCardsPerPage();
             // Adjust currentIndex in case it becomes invalid after resize
             const safeCardsPerPage = Math.max(1, cardsPerPage);
             const maxIndex = Math.max(0, totalCards - safeCardsPerPage);
             currentIndex = Math.min(currentIndex, maxIndex);
             currentIndex = Math.max(0, currentIndex); // Ensure not negative

             updateSliderPosition();
        }

        // --- Event Listeners ---
        if (nextButton && prevButton) {
             nextButton.addEventListener('click', slideNext);
             prevButton.addEventListener('click', slidePrev);
        }
        window.addEventListener('resize', handleResize);

        // --- Initial Setup ---
        requestAnimationFrame(() => {
             handleResize();
        });

    } // End if (reviewsComponent)



