    .custom-press-section {
      font-family: 'Figtree', sans-serif;
      text-align: center;
      background-color: #fff;
      color: #000;
      padding: 75px 20px;
    }

    .custom-press-section .custom-container {
      max-width: 900px;
      margin: 0 auto;
      width: 100%;
      padding: 0 20px;
    }

    .custom-press-section .custom-quote {
      font-style: italic;
      transition: opacity 0.3s ease-in-out;
      margin-bottom: 60px;
      font-size: 19px;
      font-weight: 400;
      line-height: 1.5;
    }

    .custom-press-section .custom-logos {
      display: flex;
      justify-content: center;
      gap: 20px;
      flex-wrap: wrap;
    }

    .custom-press-section .custom-logo img {
      width: 150px;
      cursor: pointer;
      opacity: 0.6;
      transition: opacity 0.3s ease-in-out;
    }

    .custom-press-section .custom-logo img:hover {
      opacity: 1;
    }

    @media (max-width: 600px) {
      .custom-press-section .custom-container {
        max-width: 100%;
        padding: 0;
      }

      .custom-press-section .custom-logos {
        gap: 10px;
      }

      .custom-press-section .custom-logo img {
        width: 100px;
      }
    }






