  document.addEventListener('DOMContentLoaded', function () {
    document.querySelectorAll('img').forEach(function (img) {
      if (!img.hasAttribute('alt') || img.getAttribute('alt').trim() === '') {

        let altText = '';

        // 1. Use data-alt if available
        if (img.dataset.alt) {
          altText = img.dataset.alt;
        }
        // 2. Use title attribute
        else if (img.getAttribute('title')) {
          altText = img.getAttribute('title');
        }
        // 3. Use image filename
        else if (img.src) {
          altText = img.src
            .split('/')
            .pop()
            .split('.')[0]
            .replace(/[-_]/g, ' ');
        }
        // 4. Final fallback
        else {
          altText = 'Image';
        }

        img.setAttribute('alt', altText);
      }
    });
  });


